const owner = $env.GITHUB_REPO_OWNER || "kreativmonkey";
const repo = $env.GITHUB_REPO_NAME || "homelab-gitops";
const token = $env.GITHUB_TOKEN;
const api = ($env.GITHUB_API_URL || "https://api.github.com").replace(/\/$/, "");
const llmBase = ($env.LLM_BASE_URL || "https://api.openai.com/v1").replace(/\/$/, "");
const llmKey = $env.LLM_API_KEY || "";
const baseUrl = api + "/repos/" + owner + "/" + repo;
const headers = { Authorization: "Bearer " + token, Accept: "application/vnd.github+json" };
const autoMergeUsers = ["renovate[bot]", "kreativmonkey"];
const PROCESSED_LABEL = "auto-merge-done";

async function gh(path, opts) {
  opts = opts || {};
  return this.helpers.httpRequest({
    method: opts.method || "GET",
    url: baseUrl + path,
    headers: headers,
    json: true,
    body: opts.body || undefined,
    timeout: 30000,
  });
}

async function addLabel(prNum) {
  try {
    await gh("/issues/" + prNum + "/labels", {
      method: "POST",
      body: { labels: [PROCESSED_LABEL] },
    });
  } catch (_) {}
}

async function getPrDiff(prNum) {
  const files = await gh("/pulls/" + prNum + "/files");
  return files.slice(0, 10).map(function(f) {
    return "File: " + f.filename + " (" + f.status + ", +" + f.additions + "/-" + f.deletions + ")\n"
      + (f.patch ? f.patch.slice(0, 2000) : "(binary or empty)");
  }).join("\n\n---\n\n");
}

async function callLlm(systemPrompt, userContent) {
  if (!llmKey) return null;
  try {
    const res = await this.helpers.httpRequest({
      method: "POST",
      url: llmBase + "/chat/completions",
      headers: {
        Authorization: "Bearer " + llmKey,
        "Content-Type": "application/json",
      },
      body: {
        model: "gpt-4o-mini",
        temperature: 0.2,
        max_tokens: 800,
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userContent },
        ],
      },
      json: true,
      timeout: 30000,
    });
    return res?.choices?.[0]?.message?.content || null;
  } catch (e) {
    return null;
  }
}

async function postAiComment(prNum, body) {
  try {
    await gh("/issues/" + prNum + "/comments", {
      method: "POST",
      body: { body: body },
    });
  } catch (_) {}
}

const prs = await gh("/pulls?state=open&per_page=50");
const results = [];

for (const pr of prs) {
  const author = pr.user.login;
  const labels = (pr.labels || []).map(function(l) { return l.name; });

  if (labels.indexOf(PROCESSED_LABEL) !== -1) continue;
  if (pr.mergeable === null) continue;

  // 1. Get diff
  const diff = await getPrDiff(pr.number);

  // 2. LLM assessment (enhanced for merge conflicts)
  let assessment = null;
  let hasConflict = false;

  try {
    let userContent = "PR #" + pr.number + " by @" + author + "\n"
      + "Title: " + (pr.title || "") + "\n\nDiff:\n" + diff;

    let systemPrompt = "You are a Kubernetes GitOps code reviewer. "
      + "Assess the PR diff for risk, correctness, and best practices. "
      + "Reply in German. Keep it under 400 characters. "
      + "Start with Risk: low/medium/high.";

    if (pr.mergeable === false) {
      userContent += "\n\nThis PR HAS A MERGE CONFLICT. "
        + "Analyze the conflict impact based on the diff. "
        + "Give resolution advice.";
      hasConflict = true;
    }

    assessment = await callLlm(systemPrompt, userContent);
  } catch (_) {}

  // 3. Post AI comment
  if (assessment) {
    let comment = "## AI Review\n\n" + assessment;
    if (hasConflict) {
      comment += "\n\n---\n⚠️ **Merge Conflict**: "
        + "This PR has conflicts. Review and resolve manually before merge.";
    }
    comment += "\n\n---\n_Automated review by n8n_";
    await postAiComment(pr.number, comment);
  }

  // 4. Author check: only autoMergeUsers are auto-merged
  if (autoMergeUsers.indexOf(author) === -1) {
    results.push({
      telegramText: "\u{1F464} *PR #" + pr.number + "* by @" + author + " (not in auto-merge allowlist)\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // 5. Merge conflict -> notify, label, skip
  if (pr.mergeable === false) {
    results.push({
      telegramText: "\u{1F6AB} *PR #" + pr.number + "* merge conflict (" + author + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
    await addLabel(pr.number);
    continue;
  }

  // 6. Check CI
  const checks = await gh("/commits/" + pr.head.sha + "/check-runs");
  const hasFailure = checks.check_runs.some(function(c) { return c.conclusion === "failure"; });
  const allSuccess = checks.check_runs.every(function(c) { return c.conclusion === "success"; });

  if (!allSuccess) {
    if (hasFailure) {
      results.push({
        telegramText: "\u274C *PR #" + pr.number + "* CI failed (" + author + ")\n"
          + (pr.title || "") + "\n"
          + pr.html_url,
        parseMode: "Markdown",
      });
      await addLabel(pr.number);
    }
    // CI pending: skip silently, retry next cycle
    continue;
  }

  // 7. CI + risk-based decision
  const riskMatch = assessment ? assessment.match(/Risiko:\s*(\w+)/i) : null;
  const isLowRisk = riskMatch && riskMatch[1].toLowerCase() === "low";

  if (isLowRisk) {
    // Auto-merge
    try {
      await gh("/pulls/" + pr.number + "/merge", {
        method: "PUT",
        body: { merge_method: "squash" },
      });
      results.push({
        telegramText: "\u2705 *PR #" + pr.number + " gemerged* (low risk)\n"
          + (pr.title || "") + "\n"
          + "_by " + author + "_",
        parseMode: "Markdown",
      });
    } catch (e) {
      results.push({
        telegramText: "\u274C *PR #" + pr.number + " merge failed*\n"
          + (pr.title || "") + "\n"
          + "_by " + author + "_\n"
          + String(e.message || e).slice(0, 200),
        parseMode: "Markdown",
      });
    }
  } else {
    // Medium/high risk -> notify
    const riskLabel = riskMatch ? riskMatch[1] : "unknown";
    results.push({
      telegramText: "\u{1F464} *PR #" + pr.number + "* by @" + author + " (risk: " + riskLabel + ")\n"
        + (pr.title || "") + "\n"
        + pr.html_url,
      parseMode: "Markdown",
    });
  }

  await addLabel(pr.number);
}

if (results.length === 0) {
  return [];
}

return results.map(function(r) { r.chatId = $env.TELEGRAM_CHAT_ID; return { json: r }; });
